Formula Details:
IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Churned Customer'), 'Churned Customer',

  IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Current Customer'), 'Current Customer',

    IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Lost Opportunity'), 'Lost Opportunity'
    & IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Cur. Effort'), ' + Cur. Effort', ''),

      IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Open Opportunity'), 'Open Opportunity',

        IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Meeting, no Opportunity'), 'Meeting, no Opportunity',

          IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Meeting Scheduled'), 'Meeting Scheduled',

            IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Past Effort'), 'Past Effort'
            & IF(NOT(ISPICKVAL(DaScoopComposer__Engagement_Status__c, 'No Engagement')), ' + Engagement', '')
            & IF(ISPICKVAL(DaScoopComposer__Engagement_Status__c, 'No Engagement'), ' no Engagement', ''),

              IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Cur. Effort'), 'Cur. Effort'
              & IF(ISPICKVAL(DaScoopComposer__Engagement_Status__c, 'Recent Engagement'), ' + Engagement', '')
              & IF(NOT(ISPICKVAL(DaScoopComposer__Engagement_Status__c, 'Recent Engagement')), ' no Engagement', ''),

                IF(INCLUDES(DaScoopComposer__Account_Tags__c, 'Untouched'), 'Untouched',
                  'Unknown'
                )
              )
            )
          )
        )
      )
    )
  )
)

IF(AND(ISBLANK(Email), ISBLANK(Phone)), "Missing - Email and Phone Number",
  IF(ISBLANK(Email), "Missing - Email",
    IF(ISBLANK(Phone), "Missing - Phone Number",
       "Complete Contact"
    )  
  )
)
